What does this program print?

```cpp
#include <iostream>

enum Season { spring, summer, autumn, winter };

std::ostream& operator<<(std::ostream& out, Season s)
{
    switch (s)
    {
        case spring: out << "spring"; break;
        case summer: out << "summer"; break;
        case autumn: out << "autumn"; break;
        case winter: out << "winter"; break;
    }
    return out;
}

int main()
{
    Season s{ autumn };
    std::cout << "Season: " << s << '\n';
    return 0;
}
```

